var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"……소란스럽군.","JPN":"……騒がしい。","ENG":"...How noisy.","TWN":"……真是吵鬧。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_35"},{"id":"L3_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"길의 끝이 막다른 곳임은 자명하건만, 우민들에겐 그 사실을 깨우치는 것조차 버거운 건가?","JPN":"行きどまりなのは確かな事実だが、愚民にはその事実を悟ることさえもできないのか？","ENG":"The path clearly ends in ruin, yet the ignorant still struggle to understand it.","TWN":"道路的盡頭顯然是死胡同，但愚民們連意識到這一事實都感到困難嗎？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_36"},{"id":"L5_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"허나 놈들이 날뛰어 준 덕에 필요로 하는 별빛은 충분히 모였다.","JPN":"だが、やつらが暴れてくれたおかげで必要な星の光は十分集まった。","ENG":"No matter. Their frenzy has gathered all the starlight I require.","TWN":"不過多虧那些傢伙鬧騰，我已經收集到了足夠的星光。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_37"},{"id":"L6_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"남은 건 인도자의 별빛을 통해 무구를 조율하는 것뿐.","JPN":"あとは導き手の星の光を通じて、武具を調律することだけ。","ENG":"All that remains is to tune the Armament through the Star Guide's light.","TWN":"剩下的只有通過引導者的星光來調節武具。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_38"},{"id":"L10_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"자아, 패배한 세계의 원념이여.","JPN":"さあ、敗北した世界の怨念よ。","ENG":"Now, grudge of a failed world...","TWN":"來吧，失敗世界的怨念啊。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_39"},{"id":"L11_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그 알량한 미련에서 벗어날 수 있도록… 내 친히 그 힘을 거두어 주마.","JPN":"そのくだらない未練から解き放たれるよう……俺がその力を引き取ってやろう。","ENG":"I shall release you from that pitiful regret. I will take that power myself.","TWN":"為了讓你擺脫那微不足道的執念……我會親自收回那股力量。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_40"},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"경계를 넘자 순식간에 풍경이 바뀌었다.","JPN":"境界を越えると、一瞬として風景が変わった。","ENG":"The moment we crossed the boundary, the landscape changed in an instant.","TWN":"一旦越過邊界，風景瞬間改變了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이전과 같은 현상을 겪는다는 건, 분명…….","JPN":"前と同じ現象を経験するということは、きっと……","ENG":"Just like before, this must be–","TWN":"經歷和以前相同的現象，分明……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"실패한 과거를 되풀이하여 제 발걸음을 돌릴 생각이시라면 안일하시군요.","JPN":"失敗した過去をくり返し、私の足を止めるつもりなら甘かったですね。","ENG":"If you thought repeating a failed past would make me retreat, you've underestimated me.","TWN":"如果你打算重蹈失敗的覆轍，那就太過輕率了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"설령 별의 인도가 제 앞길에 경종을 울린다 한들… 더는 물러서지 않습니다.","JPN":"たとえ星の導きが私の道に警鐘を鳴らすとしても……もう引き下がりません。","ENG":"Even if the stars warn me away, I will not step back.","TWN":"即便星之引導者在我面前敲響警鐘……我也絕不退縮。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"지… 켜…….","JPN":"守……れ……","ENG":"Pro... tect...","TWN":"保……護……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_10"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"그레이스 경을… 지켜라…….","JPN":"グレース卿を……守れ……","ENG":"Protect... Dame Grace...","TWN":"保護葛瑞絲……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_10"},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예.","JPN":"はい。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이번에야말로 반드시.","JPN":"今度こそ、必ず。","ENG":"I will. I promise.","TWN":"這次，一定要"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 악몽으로부터 여러분을 구원하겠습니다.","JPN":"この悪夢から皆さんを助けます。","ENG":"I will save you from this nightmare.","TWN":"我會從這個惡夢中拯救那位。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};